class Solution:
    def addedInteger(self, nums1: List[int], nums2: List[int]) -> int:
        # Calculate the difference between corresponding elements
        # Since nums2 is nums1 with x added, x = nums2[i] - nums1[i]
        # We can take the difference of any element since all elements have the same x
        return nums2[0] - nums1[0]
